package com.ichi2.anki

import androidx.test.ext.junit.runners.AndroidJUnit4
import com.ichi2.anki.cardviewer.ViewerCommand
import org.hamcrest.MatcherAssert.assertThat
import org.hamcrest.Matchers.equalTo
import org.junit.Test
import org.junit.runner.RunWith

/**
 * Test for the RESCHEDULE command functionality
 */
@RunWith(AndroidJUnit4::class)
class RescheduleCommandTest : RobolectricTest() {

    @Test
    fun rescheduleCommandExists() {
        // Verify that RESCHEDULE command is defined
        val commands = ViewerCommand.values()
        val rescheduleCommand = commands.find { it == ViewerCommand.RESCHEDULE }

        assertThat("RESCHEDULE command should exist", rescheduleCommand != null, equalTo(true))
    }

    @Test
    fun rescheduleCommandHasCorrectPreferenceKey() {
        // Verify that the preference key is correctly generated
        val preferenceKey = ViewerCommand.RESCHEDULE.preferenceKey

        assertThat("RESCHEDULE preference key should be 'binding_RESCHEDULE'", 
            preferenceKey, equalTo("binding_RESCHEDULE"))
    }
}
"}

